"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[32794],{4639:(e,a,p)=>{p.r(a),p.d(a,{data:()=>t});const t={key:"v-14ece1e0",path:"/ArcGIS/ArcMap/%E7%94%9F%E6%88%90%E5%88%87%E7%89%87%E6%96%B9%E6%A1%88.html",title:"1、生成切片方案",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"一、打开任意一个mxd文件，在Catalog中找到该数据，右键--\x3e属性--\x3e设置坐标系,此处设置空间参考应为切片所需的空间参考坐标系；",slug:"一、打开任意一个mxd文件-在catalog中找到该数据-右键-属性-设置坐标系-此处设置空间参考应为切片所需的空间参考坐标系",children:[]},{level:2,title:"二、打开ArcToolbox--\x3e数据管理工具--\x3e切片缓存--\x3e生成切片缓存切片方案工具",slug:"二、打开arctoolbox-数据管理工具-切片缓存-生成切片缓存切片方案工具",children:[]},{level:2,title:"三、输入方案数据和输出结果及位置",slug:"三、输入方案数据和输出结果及位置",children:[]},{level:2,title:"四、4.天地图切片比例级别如下",slug:"四、4-天地图切片比例级别如下",children:[]}],git:{updatedTime:1653445943e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"ArcGIS/ArcMap/生成切片方案.md"}},73067:(e,a,p)=>{p.r(a),p.d(a,{default:()=>c});const t=(0,p(57293).uE)('<h1 id="_1、生成切片方案" tabindex="-1"><a class="header-anchor" href="#_1、生成切片方案" aria-hidden="true">#</a> 1、<strong>生成切片方案</strong></h1><h2 id="一、打开任意一个mxd文件-在catalog中找到该数据-右键-属性-设置坐标系-此处设置空间参考应为切片所需的空间参考坐标系" tabindex="-1"><a class="header-anchor" href="#一、打开任意一个mxd文件-在catalog中找到该数据-右键-属性-设置坐标系-此处设置空间参考应为切片所需的空间参考坐标系" aria-hidden="true">#</a> 一、打开任意一个mxd文件，在Catalog中找到该数据，右键--&gt;属性--&gt;设置坐标系,此处设置空间参考应为切片所需的空间参考坐标系；</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032037992.jpg" alt="img"></p><h2 id="二、打开arctoolbox-数据管理工具-切片缓存-生成切片缓存切片方案工具" tabindex="-1"><a class="header-anchor" href="#二、打开arctoolbox-数据管理工具-切片缓存-生成切片缓存切片方案工具" aria-hidden="true">#</a> 二、打开ArcToolbox--&gt;数据管理工具--&gt;切片缓存--&gt;生成切片缓存切片方案工具</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032037993.jpg" alt="img"></p><h2 id="三、输入方案数据和输出结果及位置" tabindex="-1"><a class="header-anchor" href="#三、输入方案数据和输出结果及位置" aria-hidden="true">#</a> 三、输入方案数据和输出结果及位置</h2><p>a.输入数据源，选择刚刚打开的mxd文件；</p><p>b.输出切片方案，选择切片方案的存放位置及名称；</p><p>c.填写比例级数，在下方生成对应的比例，根据mxd文件的全局及放大比例尺进行设置，例如全局比例为1:25000，则可设置六级，其最小比例为1:35000最小比例为1:1000，基本满足需求；</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032037994.jpg" alt="img"></p><p>可以将原有比例删除，重新添加自定义的比例，输入完成点击确定既可以生成切片方案</p><h2 id="四、4-天地图切片比例级别如下" tabindex="-1"><a class="header-anchor" href="#四、4-天地图切片比例级别如下" aria-hidden="true">#</a> 四、4.天地图切片比例级别如下</h2><p>01 147748799.2854173</p><p>02 73874399.64270863</p><p>03 36937199.82135432</p><p>04 18468599.91067716</p><p>05 9234299.955338579</p><p>06 4617149.97766929</p><p>07 2308574.988834645</p><p>08 1154287.494417322</p><p>9 577143.74720866128</p><p>10 288571.87360433064</p><p>11 144285.93680216532</p><p>12 72142.96840108266</p><p>13 36071.48420054133</p><p>14 18035.742100270665</p><p>15 9017.8710501353326</p><p>16 4508.9355250676663</p><p>17 2254.4677625338331</p><p>18 1127.233881266917</p><p>19 563.6169406334585</p>',31),r={},c=(0,p(63243).Z)(r,[["render",function(e,a){return t}]])},63243:(e,a)=>{a.Z=(e,a)=>{const p=e.__vccOpts||e;for(const[e,t]of a)p[e]=t;return p}}}]);